// Check User History - Decide which algorithm to use
const input = $input.first().json;

const userId = input.body?.user_id || "guest_001";
const origin = input.body?.origin || "kings_cross";
const destination = input.body?.destination || "waterloo";

// Simulated user journey history (in real app, fetch from Supabase)
const userJourneyHistory = {
  "user_001": [
    { route: "northern_line", duration: 18, rating: 4 },
    { route: "circle_bakerloo", duration: 22, rating: 3 },
    { route: "northern_line", duration: 17, rating: 5 },
    { route: "victoria_jubilee", duration: 20, rating: 4 }
  ],
  "user_002": [
    { route: "circle_bakerloo", duration: 21, rating: 4 }
  ],
  "guest_001": []  // New user, no history
};

const history = userJourneyHistory[userId] || [];
const tripCount = history.length;

// Decision: Which algorithm to use?
let algorithm;
if (tripCount === 0) {
  algorithm = "collaborative_filtering";
} else if (tripCount <= 3) {
  algorithm = "hybrid";  // Mix both
} else {
  algorithm = "epsilon_greedy";
}

return {
  user_id: userId,
  origin: origin,
  destination: destination,
  trip_count: tripCount,
  history: history,
  algorithm: algorithm
};

// Epsilon-Greedy Reinforcement Learning
const input = $input.first().json;

const history = input.history;
const epsilon = 0.2; // 20% explore, 80% exploit

// Calculate average duration for each route
const routeStats = {};
history.forEach(trip => {
  if (!routeStats[trip.route]) {
    routeStats[trip.route] = { totalDuration: 0, count: 0, totalRating: 0 };
  }
  routeStats[trip.route].totalDuration += trip.duration;
  routeStats[trip.route].totalRating += trip.rating;
  routeStats[trip.route].count += 1;
});

// Find best route (lowest average duration)
let bestRoute = null;
let bestAvgDuration = Infinity;

for (const route in routeStats) {
  const avgDuration = routeStats[route].totalDuration / routeStats[route].count;
  routeStats[route].avgDuration = avgDuration;

  if (avgDuration < bestAvgDuration) {
    bestAvgDuration = avgDuration;
    bestRoute = route;
  }
}

// Epsilon-Greedy Decision
const randomValue = Math.random();
const allRoutes = ["northern_line", "circle_bakerloo", "victoria_jubilee", "elizabeth_line"];
const unknownRoutes = allRoutes.filter(r => !routeStats[r]);

let decision;
let recommendedRoute;
let reason;

if (randomValue < epsilon && unknownRoutes.length > 0) {
  // EXPLORE - try a new route
  decision = "EXPLORE";
  recommendedRoute = unknownRoutes[Math.floor(Math.random() * unknownRoutes.length)];
  reason = `Random value ${randomValue.toFixed(2)} < epsilon ${epsilon}. Trying new route!`;
} else {
  // EXPLOIT - use best known route
  decision = "EXPLOIT";
  recommendedRoute = bestRoute;
  reason = `Random value ${randomValue.toFixed(2)} >= epsilon ${epsilon}. Using best route!`;
}

return {
  algorithm: "epsilon_greedy",
  epsilon: epsilon,
  random_value: randomValue.toFixed(2),
  decision: decision,
  recommended_route: recommendedRoute,
  best_known_route: bestRoute,
  best_avg_duration: bestAvgDuration.toFixed(1) + " mins",
  route_stats: routeStats,
  reason: reason,
  user_id: input.user_id
};

// Collaborative Filtering - Recommend based on similar users
const input = $input.first().json;

const userId = input.user_id;
const origin = input.origin;
const destination = input.destination;

// Simulated user preferences database (in real app, fetch from Supabase)
const userPreferences = {
  "user_001": { time: "morning", speed: "fastest", changes: "fewest", crowd: "avoid" },
  "user_002": { time: "morning", speed: "balanced", changes: "fewest", crowd: "dont_mind" },
  "user_003": { time: "evening", speed: "fastest", changes: "dont_mind", crowd: "avoid" },
  "user_004": { time: "morning", speed: "fastest", changes: "fewest", crowd: "avoid" }
};

// Simulated journey logs - what routes similar users liked
const userFavoriteRoutes = {
  "user_001": { route: "northern_line", avg_rating: 4.5 },
  "user_002": { route: "circle_bakerloo", avg_rating: 4.0 },
  "user_003": { route: "victoria_jubilee", avg_rating: 4.2 },
  "user_004": { route: "northern_line", avg_rating: 4.8 }
};

// New user's preferences (from signup or default)
const newUserPrefs = { time: "morning", speed: "fastest", changes: "fewest", crowd: "avoid" };

// Calculate similarity with each existing user
const similarities = [];

for (const existingUser in userPreferences) {
  const existingPrefs = userPreferences[existingUser];
  let matches = 0;
  let total = 4;

  if (existingPrefs.time === newUserPrefs.time) matches++;
  if (existingPrefs.speed === newUserPrefs.speed) matches++;
  if (existingPrefs.changes === newUserPrefs.changes) matches++;
  if (existingPrefs.crowd === newUserPrefs.crowd) matches++;

  const similarity = (matches / total) * 100;

  similarities.push({
    user: existingUser,
    similarity: similarity + "%",
    matches: matches + "/4",
    favorite_route: userFavoriteRoutes[existingUser].route,
    route_rating: userFavoriteRoutes[existingUser].avg_rating
  });
}

// Sort by similarity (highest first)
similarities.sort((a, b) => parseFloat(b.similarity) - parseFloat(a.similarity));

// Recommend route from most similar user
const mostSimilarUser = similarities[0];

return {
  algorithm: "collaborative_filtering",
  new_user: userId,
  new_user_preferences: newUserPrefs,
  similar_users: similarities,
  most_similar_user: mostSimilarUser.user,
  similarity_score: mostSimilarUser.similarity,
  recommended_route: mostSimilarUser.favorite_route,
  reason: `User ${mostSimilarUser.user} has ${mostSimilarUser.similarity} similarity and loves ${mostSimilarUser.favorite_route}`
};

// Hybrid - Combine Epsilon-Greedy + Collaborative Filtering
const input = $input.first().json;

const userId = input.user_id;
const history = input.history;

// ===== PART 1: Epsilon-Greedy (from user's own history) =====
const epsilon = 0.3; // Higher exploration for new-ish users
const randomValue = Math.random();

// Calculate best route from user's limited history
const routeStats = {};
history.forEach(trip => {
  if (!routeStats[trip.route]) {
    routeStats[trip.route] = { totalDuration: 0, count: 0 };
  }
  routeStats[trip.route].totalDuration += trip.duration;
  routeStats[trip.route].count += 1;
});

let userBestRoute = null;
let bestAvgDuration = Infinity;

for (const route in routeStats) {
  const avgDuration = routeStats[route].totalDuration / routeStats[route].count;
  if (avgDuration < bestAvgDuration) {
    bestAvgDuration = avgDuration;
    userBestRoute = route;
  }
}

// ===== PART 2: Collaborative Filtering (from similar users) =====
const similarUserRecommendation = "northern_line"; // Most popular among similar users
const similarUserRating = 4.5;

// ===== PART 3: Hybrid Decision =====
let recommendedRoute;
let reason;
let method;

if (randomValue < epsilon) {
  // EXPLORE - use collaborative filtering recommendation
  method = "EXPLORE (CF)";
  recommendedRoute = similarUserRecommendation;
  reason = `Exploring! Using similar users' favorite: ${similarUserRecommendation}`;
} else {
  // EXPLOIT - use user's own best route
  method = "EXPLOIT (Own History)";
  recommendedRoute = userBestRoute;
  reason = `Exploiting! Using your best route: ${userBestRoute} (${bestAvgDuration.toFixed(1)} mins avg)`;
}

return {
  algorithm: "hybrid",
  user_id: userId,
  trip_count: history.length,
  epsilon: epsilon,
  random_value: randomValue.toFixed(2),
  method: method,
  recommended_route: recommendedRoute,
  your_best_route: userBestRoute,
  similar_users_recommend: similarUserRecommendation,
  reason: reason
};
